print(f"Number of stabilizers: {len(stabs)}")
max_len = max(len(s) for s in stabs)
print(f"Max length of stabilizer: {max_len}")


def check_stabilizers():
    try:
        with open("baseline_rq3.stim", "r") as f:
            baseline_text = f.read()
        
        circuit = stim.Circuit(baseline_text)
        print(f"Baseline qubits: {circuit.num_qubits}")
        
        sim = stim.TableauSimulator()
        sim.do(circuit)
        
        preserved = 0
        total = len(stabs)
        
        for i, stab_str in enumerate(stabs):
            try:
                pauli = stim.PauliString(stab_str)
                # If circuit has more qubits, we might need to pad the pauli string or it might auto-pad.
                # Stim usually requires lengths to match or implicit padding? 
                # Let's try as is.
                if sim.peek_observable_expectation(pauli) == 1:
                    preserved += 1
                else:
                    if i < 3:
                        print(f"Fail at index {i}")
            except Exception as e:
                print(f"Error checking stabilizer {i}: {e}")
                # Try padding
                if circuit.num_qubits > len(stab_str):
                     padded = stab_str + "I" * (circuit.num_qubits - len(stab_str))
                     pauli = stim.PauliString(padded)
                     if sim.peek_observable_expectation(pauli) == 1:
                        preserved += 1
                        if i < 3: print(f"Passed with padding at {i}")
                     else:
                        if i < 3: print(f"Failed even with padding at {i}")
        
        print(f"Preserved {preserved}/{total} stabilizers.")
    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    check_stabilizers()
